private struct GoogleCalendarTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum GoogleCalendarScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("agenda") || t.contains("schedule") || t.contains("calendar"):
            GoogleCalendarCalendarScreen()
        case let t where t.contains("task") || t.contains("tâche"):
            GoogleCalendarTasksScreen()
        default:
            GoogleCalendarGenericListScreen(title: tab)
        }
    }
}
