private struct GoogleCalendarCalendarScreen: View {
    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 16) {
                    GoogleCalendarMonthGrid(accent: GoogleCalendarTokens.gcalBlue)
                    VStack(alignment: .leading, spacing: 12) {
                        Text("Aujourd'hui").font(.headline)
                        ForEach(GoogleCalendarDemoData.events) { ev in GoogleCalendarEventRow(event: ev, accent: GoogleCalendarTokens.gcalBlue) }
                    }.padding(.horizontal)
                }.padding(.vertical)
            }.background(GoogleCalendarTokens.gcalCanvas.ignoresSafeArea()).navigationTitle("Juillet 2026")
        }
    }
}

private struct GoogleCalendarMonthGrid: View {
    let accent: Color
    var body: some View {
        VStack(spacing: 8) {
            HStack { ForEach(["L","M","M","J","V","S","D"], id: \.self) { d in Text(d).font(.caption.bold()).frame(maxWidth: .infinity) } }
            LazyVGrid(columns: Array(repeating: GridItem(.flexible()), count: 7), spacing: 8) {
                ForEach(1...30, id: \.self) { d in
                    Text("\(d)").font(.subheadline).frame(maxWidth: .infinity).padding(8)
                        .background(Circle().fill(d == 3 ? accent : Color.clear)).foregroundStyle(d == 3 ? .white : .primary)
                }
            }
        }.padding()
    }
}

private struct GoogleCalendarEventRow: View {
    let event: GoogleCalendarCalEvent; let accent: Color
    var body: some View {
        HStack(spacing: 12) {
            RoundedRectangle(cornerRadius: 2).fill(accent).frame(width: 4, height: 44)
            VStack(alignment: .leading) { Text(event.title).font(.headline); Text(event.time).font(.subheadline).foregroundStyle(.secondary) }
        }
    }
}

